      reload: configWireString(json['reload']) ?? '',
    );
  }

  final String key;
  final String type;
  final String title;
  final String description;
  final bool secret;
  final List<String> allowed;
  final List<String> actions;
  final String reload;

  Map<String, Object?> toFormField() {
    return {
      'key': key,
      'path': key,
      'title': title,
